Here are the MSTest comparison assertions you should use and a complete test class:

**Key assertions for boundary checking:**

| Assertion | Use case |
|-----------|----------|
| `Assert.IsGreaterThan(lowerBound, actual)` | Value exceeds a minimum |
| `Assert.IsLessThan(upperBound, actual)` | Value is below a maximum |
| `Assert.IsInRange(actual, low, high)` | Value falls within bounds |
| `Assert.ThrowsExactly<T>(...)` | Invalid input throws |

Here's a complete test class:

```csharp
using Contoso.Scoring;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator;

    public ScoreCalculatorTests()
    {
        _calculator = new ScoreCalculator();
    }

    // --- CalculatePercentage boundary tests ---

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        var result = _calculator.CalculatePercentage(10, 10);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_Returns0()
    {
        var result = _calculator.CalculatePercentage(0, 10);
        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_ReturnsValueInRange()
    {
        var result = _calculator.CalculatePercentage(7, 10);
        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [TestMethod]
    [DataRow(90.0, "A", DisplayName = "Exact A boundary")]
    [DataRow(89.99, "B", DisplayName = "Just below A")]
    [DataRow(80.0, "B", DisplayName = "Exact B boundary")]
    [DataRow(79.99, "C", DisplayName = "Just below B")]
    [DataRow(70.0, "C", DisplayName = "Exact C boundary")]
    [DataRow(60.0, "D", DisplayName = "Exact D boundary")]
    [DataRow(59.99, "F", DisplayName = "Just below D")]
    [DataRow(0.0, "F", DisplayName = "Zero")]
    public void GetGrade_AtBoundary_ReturnsExpectedGrade(double percentage, string expected)
    {
        var grade = _calculator.GetGrade(percentage);
        Assert.AreEqual(expected, grade);
    }

    // --- NormalizeScore boundary tests ---

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        var result = _calculator.NormalizeScore(50.0, 100.0);
        Assert.AreEqual(50.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(150.0, 100.0);
        Assert.AreEqual(100.0, result);
        // Verify it doesn't go above 100
        Assert.IsLessThan(101.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ValidInput_ReturnsValueInRange()
    {
        var result = _calculator.NormalizeScore(30.0, 80.0);
        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));
    }
}
```

**Summary of the comparison assertions:**

- **`Assert.IsInRange(actual, low, high)`** — ideal for verifying percentages stay within 0–100
- **`Assert.IsGreaterThan(lowerBound, actual)`** — confirms value exceeds a minimum (note: lower bound is the first argument)
- **`Assert.IsLessThan(upperBound, actual)`** — confirms value stays below a ceiling
- **`Assert.ThrowsExactly<T>`** — validates guard clauses throw on invalid boundaries

These require **MSTest 3.7+**. Use the `MSTest` metapackage or `MSTest.Sdk` version 3.8+ for full support.
